package main

import (
	"math"
	"sort"
)

func solve(nums []int64, queries [][]int64) []int64 {
	n := len(nums)
	q := len(queries)
	if q == 0 {
		return []int64{}
	}

	blockSize := int(math.Sqrt(float64(n)))
	if blockSize < 1 {
		blockSize = 1
	}

	type queryStruct struct {
		l, r, threshold int
		idx              int
	}

	qs := make([]queryStruct, q)
	for i := range queries {
		l := int(queries[i][0])
		r := int(queries[i][1])
		th := int(queries[i][2])
		qs[i] = queryStruct{l: l, r: r, threshold: th, idx: i}
	}

	sort.Slice(qs, func(i, j int) bool {
		blockI := qs[i].l / blockSize
		blockJ := qs[j].l / blockSize
		if blockI != blockJ {
			return blockI < blockJ
		}
		if blockI%2 == 0 {
			return qs[i].r < qs[j].r
		}
		return qs[i].r > qs[j].r
	})

	freqMap := make(map[int64]int)
	freqCount := make([]int, n+1)
	maxFreq := 0
	l, r := 0, -1

	ans := make([]int64, q)

	add := func(index int) {
		num := nums[index]
		oldCount := freqMap[num]
		freqMap[num] = oldCount + 1
		if oldCount > 0 {
			freqCount[oldCount]--
		}
		newCount := oldCount + 1
		freqCount[newCount]++
		if newCount > maxFreq {
			maxFreq = newCount
		}
	}

	remove := func(index int) {
		num := nums[index]
		oldCount := freqMap[num]
		newCount := oldCount - 1
		if newCount == 0 {
			delete(freqMap, num)
			freqCount[oldCount]--
		} else {
			freqMap[num] = newCount
			freqCount[oldCount]--
			freqCount[newCount]++
		}
		if oldCount == maxFreq && freqCount[oldCount] == 0 {
			maxFreq = oldCount - 1
		}
	}

	for _, query := range qs {
		for r < query.r {
			r++
			add(r)
		}
		for r > query.r {
			remove(r)
			r--
		}
		for l < query.l {
			remove(l)
			l++
		}
		for l > query.l {
			l--
			add(l)
		}

		if maxFreq < query.threshold {
			ans[query.idx] = -1
		} else {
			candidate := int64(math.MaxInt64)
			for num, cnt := range freqMap {
				if cnt == maxFreq && num < candidate {
					candidate = num
				}
			}
			ans[query.idx] = candidate
		}
	}

	return ans
}
```

