	}
	n := len(nums)

	set := make(map[int64]struct{})
	for _, v := range nums {
		set[v] = struct{}{}
	}
	decomp := make([]int64, 0, len(set))
	for k := range set {
		decomp = append(decomp, k)
	}
	sort.Slice(decomp, func(i, j int) bool {
		return decomp[i] < decomp[j]
	})
	compMap := make(map[int64]int)
	for i, v := range decomp {
		compMap[v] = i
	}

