	distinctList := make([]int, 0)
	distinctPos := make([]int, len(decomp))
	for i := range distinctPos {
		distinctPos[i] = -1
	}

	left := 0
	right := -1

	ans := make([]int64, qCount)

	for _, q := range qs {
		for left > q.l {
			left--
			com := compNums[left]
			freq[com]++
			if freq[com] == 1 {
				distinctList = append(distinctList, com)
				distinctPos[com] = len(distinctList) - 1
			}
