		for left < q.l {
			com := compNums[left]
			freq[com]--
			if freq[com] == 0 {
				pos := distinctPos[com]
				lastCom := distinctList[len(distinctList)-1]
				distinctList[pos] = lastCom
				distinctPos[lastCom] = pos
				distinctList = distinctList[:len(distinctList)-1]
				distinctPos[com] = -1
