				distinctList[pos] = lastCom
				distinctPos[lastCom] = pos
				distinctList = distinctList[:len(distinctList)-1]
				distinctPos[com] = -1
			}
			right--
		}

		bestFreq := -1
		bestNum := int64(-1)
		for _, com := range distinctList {
			count := freq[com]
			if count >= q.threshold {
