import (
	"math"
	"sort"
)

func solve(nums []int64, queries [][]int64) []int64 {
	n := int64(len(nums))
	numQueries := len(queries)
	if numQueries == 0 {
		return []int64{}
	}
	blockSize := int(math.Sqrt(float64(n)))
	if blockSize == 0 {
		blockSize = 1
	}

	type query struct {
		l, r, threshold int64
		index           int
	}

	qs := make([]query, numQueries)
	for i, q := range queries {
		qs[i] = query{l: q[0], r: q[1], threshold: q[2], index: i}
	}

	sort.Slice(qs, func(i, j int) bool {
		ib := qs[i].l / int64(blockSize)
		jb := qs[j].l / int64(blockSize)
		if ib != jb {
			return ib < jb
		}
		if ib%2 == 0 {
			return qs[i].r < qs[j].r
		}
		return qs[i].r > qs[j].r
	})

	res := make([]int64, numQueries)
	freq := make(map[int64]int)
	curL, curR := int64(0), int64(-1)

	for _, q := range qs {
		l, r, threshold := q.l, q.r, q.threshold
		for curR < r {
			curR++
			freq[nums[curR]]++
		}
		for curR > r {
			freq[nums[curR]]--
			if freq[nums[curR]] == 0 {
				delete(freq, nums[curR])
			}
			curR--
		}
		for curL < l {
			freq[nums[curL]]--
			if freq[nums[curL]] == 0 {
				delete(freq, nums[curL])
			}
			curL++
		}
		for curL > l {
			curL--
			freq[nums[curL]]++
		}

		best := int64(-1)
		maxCount := 0
		for num, cnt := range freq {
			if cnt >= int(threshold) {
				if cnt > maxCount {
					maxCount = cnt
					best = num
				} else if cnt == maxCount && num < best {
					best = num
				}
			}
		}
		res[q.index] = best
	}

	return res
}
